$ErrorActionPreference = "Stop"

$project = "C:\Users\arauj\grafica-flash"

if (!(Test-Path -LiteralPath $project)) {
  Write-Host "Projeto nao encontrado em $project" -ForegroundColor Red
  exit 1
}

Set-Location -LiteralPath $project

$scriptsDir = Join-Path $project "scripts"
New-Item -ItemType Directory -Force -Path $scriptsDir | Out-Null

$nodeFile = Join-Path $scriptsDir "fix-mojibake-orcaly.cjs"

$base64 = @"

"@

$bytes = [System.Convert]::FromBase64String($base64.Trim())
$content = [System.Text.Encoding]::UTF8.GetString($bytes)
$utf8NoBom = New-Object System.Text.UTF8Encoding($false)
[System.IO.File]::WriteAllText($nodeFile, $content, $utf8NoBom)

Write-Host "Corretor Node criado em scripts\fix-mojibake-orcaly.cjs" -ForegroundColor Green
Write-Host "Rodando correcao de acentos..." -ForegroundColor Cyan

node $nodeFile

if ($LASTEXITCODE -ne 0) {
  Write-Host "Falha ao rodar o corretor Node." -ForegroundColor Red
  exit $LASTEXITCODE
}

Write-Host ""
Write-Host "Correcao finalizada. Rode npm run build." -ForegroundColor Yellow
